def bitwise_sum(nums: Any) -> object {
    total = 0;
    carry = 0;
    for num in nums {
        total ^= num;
        carry |= num & carry;
        carry <<= 1;
    }
    while carry {
        total ^= carry;
        carry <<= 1;
    }
    return total;
}



